using System;
using System.Collections.Generic;
using System.Data;
using System.Data.SqlClient;
using System.Linq;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Azure.WebJobs;
using Microsoft.Azure.WebJobs.Extensions.Http;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Logging;

public static class QueryFunction
{
    [FunctionName("QueryDatabase")]
    public static async Task<IActionResult> Run(
        [HttpTrigger(AuthorizationLevel.Function, "get", "post", Route = null)] HttpRequest req,
        ILogger log)
    {
        try
        {
            var connectionString = Environment.GetEnvironmentVariable("SqlConnectionString");
            var parameters = new Dictionary<string, object>();
            var conditions = new List<string>();
            var sql = "SELECT * FROM YourTable WHERE 1=1";

            foreach (var param in req.Query)
            {
                if (!string.IsNullOrEmpty(param.Value.ToString()))
                {
                    var columnName = param.Key;
                    var value = param.Value.ToString();
                    var condition = BuildCondition(columnName, value);
                    conditions.Add(condition);
                }
            }

            if (conditions.Any())
            {
                sql += " AND " + string.Join(" AND ", conditions);
            }

            using (var connection = new SqlConnection(connectionString))
            {
                await connection.OpenAsync();
                using (var command = new SqlCommand(sql, connection))
                {
                    foreach (var param in parameters)
                    {
                        command.Parameters.AddWithValue(param.Key, param.Value);
                    }

                    using (var reader = await command.ExecuteReaderAsync())
                    {
                        var results = new List<Dictionary<string, object>>();
                        while (await reader.ReadAsync())
                        {
                            var row = new Dictionary<string, object>();
                            for (int i = 0; i < reader.FieldCount; i++)
                            {
                                row[reader.GetName(i)] = reader.GetValue(i);
                            }
                            results.Add(row);
                        }
                        return new OkObjectResult(results);
                    }
                }
            }
        }
        catch (Exception ex)
        {
            return new StatusCodeResult(500);
        }
    }

    private static string BuildCondition(string columnName, string value)
    {
        var parameterName = $"@{columnName}";
        if (value.Contains(","))
        {
            var values = value.Split(',').Select(v => v.Trim()).ToArray();
            var inClause = string.Join(",", values.Select((v, i) => $"@param{i}"));
            return $"{columnName} IN ({inClause})";
        }
        else if (value.Contains("*"))
        {
            var pattern = value.Replace("*", "%");
            return $"{columnName} LIKE {parameterName}";
        }
        else
        {
            return $"{columnName} = {parameterName}";
        }
    }
